import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios";

const CategoryGalleryPage = () => {
  const { section, category } = useParams();
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchImages = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/gallery`);
        const filtered = res.data.filter(
          (img) =>
            img.Category?.name.toLowerCase() === category &&
            img.Category?.section.toLowerCase() === section
        );
        setImages(filtered);
      } catch (error) {
        console.error("Failed to fetch images", error);
      } finally {
        setLoading(false);
      }
    };

    fetchImages();
  }, [section, category]);

  return (
    <div className="min-h-screen bg-gray-100 py-10 px-4">
      <div className="max-w-6xl mx-auto text-center">
        <h2 className="text-4xl font-bold mb-2 capitalize text-gray-800">
          {category.replace("-", " ")} Gallery
        </h2>
        <p className="text-gray-500 mb-8 text-sm uppercase tracking-wide">
          Section: {section.replace("-", " ")}
        </p>
      </div>

      {loading ? (
        <div className="text-center text-lg text-gray-600">Loading...</div>
      ) : images.length === 0 ? (
        <div className="text-center text-gray-600 mt-20">No images found in this category.</div>
      ) : (
        <div className="max-w-6xl mx-auto grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
          {images.map((img) => (
            <div key={img.id} className="bg-white rounded-lg shadow hover:shadow-xl transition">
              <img
                src={`http://localhost:5000${img.imageUrl}`}
                alt={img.title}
                className="w-full h-60 object-cover rounded-t-lg"
              />
              <div className="p-4 text-center">
                <h3 className="text-lg font-semibold text-gray-800">{img.title}</h3>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CategoryGalleryPage;
